content:
slide-1 .tag-amber { background: rgba(245,158,11,0.15); color: var(--accent-amber); border: 1px solid rgba(245,158,11,0.3); }
  .slide-1 .tag-purple { background: rgba(139,92,246,0.15); color: var(--accent-purple); border: 1px solid rgba(139,92,246,0.3); }
  /* ════════════════════════════════════════════════════ */
  /* SLIDE 2 — THE WHY                                  */
  /* ════════════════════════════════════════════════════ */
  .slide-2 { background: var(--bg-dark); }
  .slide-2 .slide-label { color: var(--accent-blue); }

  .slide-2 .motivation-list {
    display: flex;
    flex-direction: column;
    gap: 20px;
    margin-bottom: 36px;
  }
  .slide-2 .motivation-item {
    display: flex;
    gap: 18px;
    align-items: flex-start;
  }
  .slide-2 .motivation-item .m-icon { font-size: 32px; flex-shrink: 0; margin-top: 2px; }
  .slide-2 .motivation-item .m-text {
    font-size: 24px;
    font-weight: 500;
    color: var(--text-primary);
    line-height: 1.5;
  }

  .slide-2 .distinction {
    display: flex;
    gap: 20px;
  }
  .slide-2 .distinction-card {
    flex: 1;
    min-width: 0;
    background: var(--bg-card);
    border-radius: 16px;
    padding: 32px;
  }
  .slide-2 .d-label {
    font-size: 16px;
    font-weight: 700;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    margin-bottom: 16px;
  }
  .slide-2 .d-example {
    font-size: 22px;
    font-weight: 500;
    color: var(--text-secondary);
    line-height: 1.5;
    font-style: italic;
  }
  .slide-2 .d-note {
    font-size: 17px;
    font-weight: 600;
    margin-top: 16px;
    padding-top: 12px;
    border-top: 1px solid var(--border);
  }
